// // Asynchronous reset should set Q to 1 on reset
module d_flip_flop (  
    input clk,  
    input reset,  
    input D,  
    output reg Q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            Q <= 0;  
        end else begin  
            Q <= D;  
        end  
    end  
endmodule
